class ProjectUploader {
    var onComplete: (() -> Void)?

    func start() {
        // Use [weak self] to prevent a memory leak
        onComplete = { [weak self] in
            self?.notifyUser()
        }
    }

    func notifyUser() { print("Upload finished") }
}
